```typescript
// notification.hooks.ts
import { createContext, useContext, useState, useEffect } from 'react';
import { HTMLHuelNotificationElement } from 'h-notify';

interface NotificationProps {
  heading: string;
  subheading: string;
  type: string;
}

interface NotificationContextType {
  notification: HTMLHuelNotificationElement | null;
  notify: (props: NotificationProps) => Promise<void>;
}

const NotificationContext = createContext<NotificationContextType | null>(null);

export const useNotification = () => {
  const notification = useContext(NotificationContext);
  const [notificationElem, setNotificationElem] = useState<HTMLHuelNotificationElement | null>(null);

  useEffect(() => {
    const elem = notification?.notification;
    if (elem) {
      setNotificationElem(elem);
    }
  }, [notification]);

  const notify = async (props: NotificationProps) => {
    if (!notificationElem) return;

    const { heading, subheading, type } = props;
    await notificationElem.open({
      heading,
      subheading,
      type,
    });
  };

  return { notificationElem, notify };
};

