public class BaseRepository<T> where T : class
{
    private readonly DbContext _context;
    private readonly DbSet<T> _dbSet;

    public BaseRepository(DbContext context)
    {
        _context = context;
        _dbSet = context.Set<T>();
    }

    public virtual IQueryable<T> GetAll()
    {
        return _dbSet;
    }

    public virtual T GetById(object id)
    {
        return _dbSet.Find(id);
    }

    public virtual IQueryable<T> FindByDynamic(Expression<Func<T, bool>> predicate)
    {
        return _dbSet.AsQueryable().Where(predicate);
    }

    public virtual T FindByDynamicSingle(Expression<Func<T, bool>> predicate)
    {
        return _dbSet.AsQueryable().FirstOrDefault(predicate);
    }
}
```

